={
  "query_text": "SELECT s.token_id, s.probability, s.signal, s.prediction, s.model_name, s.model_version, s.scored_at, t.name, t.symbol, t.chain, t.pool_address FROM scores s JOIN tokens t ON s.token_id = t.token_id WHERE s.scored_at::date = CURRENT_DATE AND s.signal IN ('STRONG','MEDIUM') ORDER BY s.probability DESC LIMIT 10"
}

