// === Auto Post Daily Signals — Code Node ===
// Lee los scores del dia desde Supabase y formatea el mensaje
// para Telegram (y futuro Twitter).

const items = $input.all();
const today = new Date().toISOString().slice(0, 10);

// Verificar si hubo error en la query
if (!items || items.length === 0 || items[0].json?.error) {
  const errorMsg = items?.[0]?.json?.message || items?.[0]?.json?.error || 'Error desconocido';
  return [{
    json: {
      telegram_text: `\u26a0\ufe0f <b>Meme Detector</b> — ${today}\n\nNo se pudieron obtener las senales de hoy.\nError: ${errorMsg}\n\nVerificar daily-collect workflow.`,
      tweet_text: `\u26a0\ufe0f Meme Detector — Sin senales hoy (${today}). Verificando sistema...`,
      has_signals: false
    }
  }];
}

// Parsear resultados — exec_query devuelve array de rows
let candidates = [];
if (Array.isArray(items[0].json)) {
  candidates = items[0].json;
} else if (items[0].json?.result && Array.isArray(items[0].json.result)) {
  candidates = items[0].json.result;
} else {
  // Intentar con todos los items como filas individuales
  candidates = items.map(i => i.json).filter(j => j.token_id);
}

if (candidates.length === 0) {
  return [{
    json: {
      telegram_text: `\u{1f48e} <b>Senales del dia</b> — ${today}\n\nSin senales gem hoy. El modelo no detecto candidatos con probabilidad suficiente.\n\n\u{1f4ca} Modelo v16 | F1: 0.839`,
      tweet_text: `\u{1f48e} Senales del dia — Meme Detector\n\nSin candidatos gem hoy. El modelo analizo +5,000 tokens pero ninguno supero el umbral.\n\n\u{1f4ca} Modelo v16 | F1: 0.839\n\u26a0\ufe0f No es consejo financiero`,
      has_signals: false
    }
  }];
}

// --- Formatear mensaje Telegram (HTML) ---
const signalEmoji = { STRONG: '\u{1f7e2}', MEDIUM: '\u{1f7e1}', WEAK: '\u{1f7e0}' };
const chainLabel = { solana: 'Solana', ethereum: 'ETH', base: 'Base' };

let tgMsg = `\u{1f48e} <b>Senales del dia</b> — Meme Detector\n<i>${today}</i>\n\n`;

// Top 3 para version publica
const top3 = candidates.slice(0, 3);
top3.forEach((c, i) => {
  const emoji = signalEmoji[c.signal] || '\u26aa';
  const chain = chainLabel[c.chain] || c.chain || '?';
  const prob = (c.probability * 100).toFixed(0);
  const symbol = c.symbol || c.name || c.token_id.slice(0, 8);
  const dexLink = `https://dexscreener.com/${c.chain}/${c.pool_address || c.token_id}`;

  tgMsg += `${emoji} <b>$${symbol}</b> (${chain}) — Score: ${prob}% ${c.signal}\n`;
  tgMsg += `    <a href="${dexLink}">Ver en DexScreener</a>\n\n`;
});

if (candidates.length > 3) {
  tgMsg += `+${candidates.length - 3} senales mas en memedetector.es (Pro)\n\n`;
}

const version = candidates[0]?.model_version || 'v16';
tgMsg += `\u{1f4ca} Modelo ${version} | F1: 0.839\n`;
tgMsg += `\u26a0\ufe0f No es consejo financiero. DYOR.\n\n`;
tgMsg += `Mas senales \u2192 memedetector.es`;

// --- Formatear tweet (texto plano, max ~280 chars) ---
let tweetMsg = `\u{1f48e} Senales del dia — Meme Detector\n\n`;
top3.forEach(c => {
  const emoji = signalEmoji[c.signal] || '\u26aa';
  const chain = chainLabel[c.chain] || c.chain || '?';
  const prob = (c.probability * 100).toFixed(0);
  const symbol = c.symbol || c.name || '???';
  tweetMsg += `${emoji} $${symbol} (${chain}) — Score: ${prob}% ${c.signal}\n`;
});
tweetMsg += `\n\u{1f4ca} Modelo ${version} | F1: 0.839\n`;
tweetMsg += `\u26a0\ufe0f No es consejo financiero\n\n`;
tweetMsg += `Mas senales \u2192 memedetector.es`;

return [{
  json: {
    telegram_text: tgMsg,
    tweet_text: tweetMsg,
    has_signals: true,
    signal_count: candidates.length,
    top_signals: top3.map(c => ({
      symbol: c.symbol,
      chain: c.chain,
      probability: c.probability,
      signal: c.signal
    }))
  }
}];

// === Twitter Post Placeholder ===
// TODO: Cuando se obtenga Twitter API key ($100/mes plan Basic),
// reemplazar este nodo por un HTTP Request a:
//   POST https://api.twitter.com/2/tweets
//   Headers: Authorization: Bearer {TWITTER_BEARER_TOKEN}
//   Body: { "text": $json.tweet_text }
//
// Por ahora, solo logueamos el tweet que se publicaria.

const tweet = $input.first().json.tweet_text;

console.log('=== TWEET QUE SE PUBLICARIA ===');
console.log(tweet);
console.log('=== FIN TWEET ===');
console.log(`Caracteres: ${tweet.length}/280`);

return [{
  json: {
    status: 'twitter_not_configured',
    message: 'Twitter API no configurada. Tweet preparado pero no enviado.',
    tweet_text: tweet,
    char_count: tweet.length,
    within_limit: tweet.length <= 280
  }
}];
